/**이북 리스트*/
SELECT A.* FROM (

	SELECT A.*
	FROM T_EBOOK A
	WHERE 1


) A
ORDER BY IDX desc
limit #{firstRecordIndex},#{recordCountPerPage}

mapper.update:
/** 이북 수정 */
UPDATE T_EBOOK 
SET
	TITLE=#{title}
	,START_DTIME=#{startDtime}
	,END_DTIME=#{endDtime}
	,STATUS=#{status}
	,URL=#{url}
	,SORT=#{sort}
WHERE
	IDX=#{idx}

UPDATE T_EBOOK
FILE_NM=#{fileNm}, FILE_RENM=#{fileRenm}, THUM_NM=#{thumNm}, THUM_RENM=#{thumRenm},
WHERE IDX=#{idx}
